using System;
using System.Collections.Generic;
using System.Xml;

public class XmlConfigParser
{
    public Dictionary<string, string> ParseXmlConfig(string xmlContent)
    {
        var settings = new Dictionary<string, string>();
        var xmlReaderSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD
        };

        using (var reader = XmlReader.Create(new System.IO.StringReader(xmlContent), xmlReaderSettings))
        {
            var doc = new XmlDocument();
            doc.Load(reader);

            var nodes = doc.SelectNodes("//setting");
            if (nodes != null)
            {
                foreach (XmlNode node in nodes)
                {
                    if (node.Attributes != null)
                    {
                        var key = node.Attributes["name"]?.InnerText;
                        var value = node.Attributes["value"]?.InnerText;

                        if (!string.IsNullOrEmpty(key))
                        {
                            settings[key] = value;
                        }
                    }
                }
            }
        }

        return settings;
    }
}